# Animated Input

Orb input field with a GIF avatar orb, animated typewriter placeholder cycling through multiple prompts, and a focus scale/shadow transition. Pure React with no animation library — uses setInterval-based character typing and CSS transitions.

## Use when
- Building an AI chat or assistant interface with an engaging animated input.
- Adding a search input with a personality-driven animated placeholder.
- Creating an onboarding prompt that draws attention to the input field.

## Stack
- Framework: react
- Libraries: none
- Requires: tailwind

## Install
```bash
none
```

## Component — animated-input.tsx
```tsx
"use client"

import React, { useEffect, useMemo, useRef, useState } from "react"

export function OrbInput() {
  const [value, setValue] = useState("")
  const [isFocused, setIsFocused] = useState(false)
  const [placeholderIndex, setPlaceholderIndex] = useState(0)
  const [displayedText, setDisplayedText] = useState("")
  const [isTyping, setIsTyping] = useState(true)

  const placeholders = useMemo(
    () => [
      "Ask anything...",
      "What's on your mind?",
      "How can I help you?",
      "What would you like to know?",
    ],
    []
  )

  const CHAR_DELAY = 75
  const IDLE_DELAY_AFTER_FINISH = 2200

  const intervalRef = useRef(null)
  const timeoutRef = useRef(null)

  useEffect(() => {
    if (intervalRef.current) { clearInterval(intervalRef.current); intervalRef.current = null; }
    if (timeoutRef.current) { clearTimeout(timeoutRef.current); timeoutRef.current = null; }

    const current = placeholders[placeholderIndex]
    if (!current) { setDisplayedText(""); setIsTyping(false); return; }

    const chars = Array.from(current)
    setDisplayedText("")
    setIsTyping(true)
    let charIndex = 0

    intervalRef.current = window.setInterval(() => {
      if (charIndex < chars.length) {
        const next = chars.slice(0, charIndex + 1).join("")
        setDisplayedText(next)
        charIndex += 1
      } else {
        if (intervalRef.current) { clearInterval(intervalRef.current); intervalRef.current = null; }
        setIsTyping(false)
        timeoutRef.current = window.setTimeout(() => {
          setPlaceholderIndex((prev) => (prev + 1) % placeholders.length)
        }, IDLE_DELAY_AFTER_FINISH)
      }
    }, CHAR_DELAY)

    return () => {
      if (intervalRef.current) { clearInterval(intervalRef.current); intervalRef.current = null; }
      if (timeoutRef.current) { clearTimeout(timeoutRef.current); timeoutRef.current = null; }
    }
  }, [placeholderIndex, placeholders])

  return (
    <div className="relative">
      <div
        className={`flex items-center gap-4 p-6 bg-black shadow-lg transition-all duration-300 ease-out rounded-full border border-gray-300 ${
          isFocused ? "shadow-xl scale-[1.02] border-gray-600" : "shadow-lg"
        }`}
      >
        <div className="relative flex-shrink-0">
          <div className="w-16 h-16 rounded-full overflow-hidden transition-all duration-300 scale-100">
            <img
              src="https://media.giphy.com/media/26gsuUjoEBmLrNBxC/giphy.gif"
              alt="Animated orb"
              className="w-full h-full object-cover"
            />
          </div>
        </div>

        <div className="w-px h-12 bg-gray-600" />

        <div className="flex-1 w-[500px]">
          <input
            data-testid="orb-input"
            type="text"
            value={value}
            onChange={(e) => setValue(e.target.value)}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            placeholder={`${displayedText}${isTyping ? "|" : ""}`}
            aria-label="Ask a question"
            className="w-full text-xl text-white placeholder-gray-400 bg-transparent border-none outline-none font-light"
          />
        </div>
      </div>
    </div>
  )
}

export default OrbInput
```

## Demo
```tsx
import { OrbInput } from "@/components/ui/animated-input";

export default function DemoOne() {
  return <OrbInput />;
}
```

## Notes
- The orb avatar uses an external Giphy GIF URL (`https://media.giphy.com/media/26gsuUjoEBmLrNBxC/giphy.gif`). Replace with a local asset or different URL for production.
- The input has a fixed `w-[500px]` width on the text container — this may overflow on small viewports. Adjust to `w-full` or a responsive value as needed.
